// Vertex Shader
attribute vec3 position;
attribute vec3 normal;

uniform mat4 modelViewMatrix;
uniform mat4 normalMatrix;
uniform mat4 projectionMatrix;

varying vec3 vNormal;
varying vec3 vPosition;

void main() {
    vPosition = (modelViewMatrix * vec4(position, 1.0)).xyz;
    vNormal = normalize((normalMatrix * vec4(normal, 0.0)).xyz);
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}

// Fragment Shader (Phong Shading - computed per pixel)
precision mediump float;

varying vec3 vNormal;
varying vec3 vPosition;

uniform vec3 lightPosition;  // in view space
uniform vec3 lightColor;
uniform vec3 ambientColor;
uniform float ka, kd, ks;    // material properties
uniform float shininess;

void main() {
    // Normalize interpolated normal
    vec3 N = normalize(vNormal);

    // Light direction
    vec3 L = normalize(lightPosition - vPosition);

    // View direction (camera at origin in view space)
    vec3 V = normalize(-vPosition);

    // Reflection vector: R = 2(N·L)N - L
    vec3 R = reflect(-L, N);

    // Ambient component
    vec3 ambient = ka * ambientColor;

    // Diffuse component (Lambert)
    float diff = max(dot(N, L), 0.0);
    vec3 diffuse = kd * lightColor * diff;

    // Specular component (Phong)
    float spec = pow(max(dot(R, V), 0.0), shininess);
    vec3 specular = ks * lightColor * spec;

    // Final color
    vec3 finalColor = ambient + diffuse + specular;
    gl_FragColor = vec4(finalColor, 1.0);
}
